std::string_view PinyinFullSyllableForCodepoint(wchar_t ch)
{
    if (ch < kCjkStart || ch > kCjkEnd)
        return {};

    const unsigned short id = kPinyinSyllableIds[static_cast<size_t>(ch - kCjkStart)];
    if (id == 0 || id >= kPinyinSyllableOffsets.size())
        return {};

    return std::string_view(kPinyinSyllablePool + kPinyinSyllableOffsets[id]);
}
